import { z } from "zod";

export const shortenRequestSchema = z.object({
  url: z.string().url().max(2048),
  customCode: z
    .string()
    .regex(/^[a-zA-Z0-9_-]+$/)
    .min(3)
    .max(32)
    .optional(),
});

export const shortenResponseSchema = z.object({
  code: z.string(),
  shortUrl: z.string(),
  targetUrl: z.string(),
  qrCode: z.string().optional(),
});

export const shortUrlStatsSchema = z.object({
  code: z.string(),
  targetUrl: z.string(),
  clicks: z.number(),
  createdAt: z.string(),
});

export type ShortenRequest = z.infer<typeof shortenRequestSchema>;
export type ShortenResponse = z.infer<typeof shortenResponseSchema>;
export type ShortUrlStats = z.infer<typeof shortUrlStatsSchema>;
